# Shapes module - abstract classes and implementations
from types import Color, Point, Status

@abstract
class Shape:
    _color: Color
    _status: Status

    def __init__(self, color: Color):
        self._color = color
        self._status = Status.PENDING

    def get_color(self) -> Color:
        return self._color

    def set_status(self, status: Status) -> None:
        self._status = status

    def get_status(self) -> Status:
        return self._status

    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

    @virtual
    def draw(self) -> str:
        return f"Shape(color={self.get_color().name})"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color):
        super().__init__(color)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def draw(self) -> str:
        return f"Rectangle({self.width}x{self.height}, {self.get_color().name})"

class Circle(Shape):
    @static
    PI: float = 3.14159

    radius: float
    center: Point

    def __init__(self, radius: float, center: Point, color: Color):
        super().__init__(color)
        self.radius = radius
        self.center = center

    @override
    def area(self) -> float:
        return Circle.PI * self.radius ** 2.0

    @override
    def perimeter(self) -> float:
        return 2.0 * Circle.PI * self.radius

    @override
    def draw(self) -> str:
        return f"Circle(r={self.radius}, {self.get_color().name})"

    def get_center_distance(self) -> float:
        return self.center.distance_from_origin()

class Triangle(Shape):
    base: float
    side: float

    def __init__(self, base: float, side: float, color: Color):
        super().__init__(color)
        self.base = base
        self.side = side

    @override
    def area(self) -> float:
        # Using Heron's formula for isosceles triangle
        a: float = self.side
        b: float = self.side
        c: float = self.base
        s: float = (a + b + c) / 2.0
        return (s * (s - a) * (s - b) * (s - c)) ** 0.5

    @override
    def perimeter(self) -> float:
        return 2.0 * self.side + self.base

    @override
    def draw(self) -> str:
        return f"Triangle(b={self.base}, s={self.side}, {self.get_color().name})"
